          │     ├── <div class="form-field"> (Password)
          │     │   ├── <div class="forgot-password-row">
          │     │   │   ├── <label>Password</label>
          │     │   │   └── <button class="link-button">Forgot password?</button>
          │     │   └── <div class="input-with-action">
          │     │       ├── <input ... />
          │     │       └── <button class="show-toggle">Show/Hide</button>
