  font-size: 1.6rem;
  font-weight: 780; /* Extra bold */
}

.auth-modal-message {
  text-align: center;
  font-size: 0.95rem;
  color: var(--text-secondary);
  margin: 0;
}
```

**Buttons Container:**
```css
.auth-modal-buttons {
  display: flex;
  gap: 0.75rem;
  width: 100%;
}
```

**Login Button (Filled/Primary):**
```css
.auth-modal-login-bttn {
  flex: 1;
  padding: 0.6rem 1rem;
  background-color: var(--text-heading); /* Solid dark */
  color: var(--bg-primary); /* Light text */
  border: 2px solid var(--text-heading);
  border-radius: 8px;
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  transition: opacity 0.15s;
}

.auth-modal-login-bttn:hover {
  opacity: 0.85;
}
```

**Signup Button (Outlined/Secondary):**
```css
.auth-modal-signup-bttn {
  flex: 1;
  padding: 0.6rem 1rem;
  background-color: var(--bg-card); /* Transparent */
